1	const PROCESSING_FEE = 5;
2	const DEDUCTIBLE = 100;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	const INSURANCE_VALUES: Record<string, number> = {
13	  sword: 1000,
14	  amulet: 600,
15	  staff: 800,
16	  potion: 400,
17	};
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	const COMPONENT_PREMIUM = 25;
23	
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_QUOTE_THRESHOLD = 5;
26	const HIGH_ENCHANTMENT_QUOTE_SURCHARGE_RATE = 0.3;
27	
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_MIN_YEARS = 2;
30	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
31	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
32	
33	const calculateItemSurcharges = (item: any, base: number): number => {
34	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
35	  const enchantmentSurcharge =
36	    item.enchantment >= HIGH_ENCHANTMENT_QUOTE_THRESHOLD
37	      ? base * HIGH_ENCHANTMENT_QUOTE_SURCHARGE_RATE
38	      : 0;
39	  return curseSurcharge + enchantmentSurcharge;
40	};
41	
42	const calculateComponentsCost = (items: any[]): number => {
43	  const componentCounts: Record<string, number> = {};
44	  for (const item of items) {
45	    if (COMPONENT_TYPES.has(item.type)) {
46	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
47	    }
48	  }
49	  return Object.values(componentCounts).reduce((total, count) => {
50	    return total + (count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM);
51	  }, 0);
52	};
53	
54	const calculatePolicyModifiers = (basePremium: number, customer: any, quoteIndex: number): number => {
55	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
56	    ? basePremium * LOYALTY_DISCOUNT_RATE
57	    : 0;
58	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
59	  const followUpDiscount = quoteIndex > 0
60	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
61	    : 0;
62	  return firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount;
63	};
64	
65	const calculateQuotePremium = (items: any[], customer: any, quoteIndex: number): { premium: number } => {
66	  const equipmentItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
67	
68	  const equipmentBasePremium = equipmentItems.reduce(
69	    (sum, item) => sum + (BASE_PREMIUMS[item.type] || 0),
70	    0
71	  );
72	  const itemSurcharges = equipmentItems.reduce(
73	    (sum, item) => sum + calculateItemSurcharges(item, BASE_PREMIUMS[item.type] || 0),
74	    0
75	  );
76	  const componentsCost = calculateComponentsCost(items);
77	
78	  const policyBasePremium = equipmentBasePremium + componentsCost;
79	  const policyModifiers = calculatePolicyModifiers(policyBasePremium, customer, quoteIndex);
80	
81	  return { premium: Math.ceil(policyBasePremium + itemSurcharges + policyModifiers + PROCESSING_FEE) };
82	};
83	
84	const COMPONENT_INSURANCE_VALUE = 250;
85	
86	const calculateInsuranceSum = (items: any[]): number => {
87	  return items.reduce((sum, item) => {
88	    if (COMPONENT_TYPES.has(item.type)) {
89	      return sum + COMPONENT_INSURANCE_VALUE;
90	    }
91	    return sum + (INSURANCE_VALUES[item.type] || 0);
92	  }, 0);
93	};
94	
95	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
96	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
97	
98	const processClaim = (step: any, policies: any[]): { payout: number; remainingCap: number } => {
99	  const policy = policies[step.policy];
100	  const totalPayout = step.incident.damages.reduce((sum: number, damage: any) => {
101	    const policyItem = policy.items.find((item: any) => item.type === damage.itemType);
102	    const reimbursement = policyItem && policyItem.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
103	      ? damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE
104	      : damage.amount;
105	    return sum + Math.max(0, reimbursement - DEDUCTIBLE);
106	  }, 0);
107	  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
108	  policy.remainingCap -= cappedPayout;
109	  return { payout: Math.floor(cappedPayout), remainingCap: policy.remainingCap };
110	};
