112	export const processScenario = (scenario: any): any => {
113	  const policies: any[] = [];
114	  let quoteIndex = 0;
115	  const results = scenario.steps.map((step: any) => {
116	    if (step.op === "claim") {
117	      return processClaim(step, policies);
118	    }
119	    const result = calculateQuotePremium(step.items, scenario.customer, quoteIndex);
120	    const insuranceSum = calculateInsuranceSum(step.items);
121	    policies.push({
122	      items: step.items,
123	      insuranceSum,
124	      remainingCap: insuranceSum * 2,
125	    });
126	    quoteIndex++;
127	    return result;
128	  });
129	  return { results };
130	};
